using UnityEngine;
using UnityEngine.Purchasing;

public class PlayerStats : MonoBehaviour
{
    [Header("Core Stats (Public)")]
    public int maxHealth = 100;
    public int currentHealth = 100;
    public int currency = 0;

    [Header("Combat (Public)")]
    public int baseDamage = 10;
    public float damageMultiplier = 1f;
    public int flatDamageBonus = 0;
    public float critChance = 0.1f;   // 0..1
    public float critMultiplier = 2f; // >=1

    [Header("Defense (Public)")]
    public int armor = 0;             // flat reduction
    public float damageReduction = 0f; // 0..0.9 recommended

    [Header("Economy (Public)")]
    public float shopPriceMultiplier = 1f;

    public bool IsAlive => currentHealth > 0;

    void Awake()
    {
        ClampAll();
        if (currentHealth <= 0) currentHealth = maxHealth;
    }

    public void ClampAll()
    {
        if (maxHealth < 1) maxHealth = 1;
        currentHealth = Mathf.Clamp(currentHealth, 0, maxHealth);
        if (currency < 0) currency = 0;

        if (damageMultiplier < 0f) damageMultiplier = 0f;
        if (critChance < 0f) critChance = 0f;
        if (critChance > 1f) critChance = 1f;
        if (critMultiplier < 1f) critMultiplier = 1f;

        if (armor < 0) armor = 0;
        if (damageReduction < 0f) damageReduction = 0f;
        if (damageReduction > 0.95f) damageReduction = 0.95f;

        if (shopPriceMultiplier < 0f) shopPriceMultiplier = 0f;
    }

    public void Heal(int amount)
    {
        if (amount <= 0) return;
        currentHealth = Mathf.Clamp(currentHealth + amount, 0, maxHealth);
    }

    public int TakeDamage(int incomingDamage)
    {
        if (incomingDamage <= 0) return 0;

        int reduced = Mathf.Max(0, incomingDamage - armor);
        float afterPercent = reduced * (1f - damageReduction);
        int final = Mathf.Max(0, Mathf.RoundToInt(afterPercent));

        currentHealth = Mathf.Clamp(currentHealth - final, 0, maxHealth);
        return final;
    }

    public int CalculateOutgoingDamage(bool allowCrit = true)
    {
        float dmg = (baseDamage + flatDamageBonus) * damageMultiplier;
        if (dmg < 0f) dmg = 0f;

        if (allowCrit && Random.value < critChance)
            dmg *= critMultiplier;

        return Mathf.Max(0, Mathf.RoundToInt(dmg));
    }

    public bool SpendCurrency(int amount)
    {
        if (amount <= 0) return true;
        if (currency < amount) return false;
        currency -= amount;
        return true;
    }

    public void AddCurrency(int amount)
    {
        if (amount <= 0) return;
        currency += amount;
    }

    public void SetCurrency(int amount)
    {
        currency = Mathf.Max(0, amount);
    }

    public void SetMaxHealth(int newMax, bool healToFull = false)
    {
        maxHealth = Mathf.Max(1, newMax);
        if (healToFull) currentHealth = maxHealth;
        else currentHealth = Mathf.Clamp(currentHealth, 0, maxHealth);
    }
}

public enum ShopItemType
{
    Heal,
    MaxHealthUpgrade,
    BaseDamageUpgrade,
    DamageMultiplierUpgrade,
    FlatDamageUpgrade,
    ArmorUpgrade,
    DamageReductionUpgrade
}

[System.Serializable]
public class ShopItemDefinition
{
    public string id;
    public string displayName;
    public ShopItemType type;

    [Header("Pricing")]
    public int basePrice = 10;
    public float priceGrowth = 1.15f;
    public int priceAddPerPurchase = 0;

    [Header("Effect")]
    public int intAmount = 0;
    public float floatAmount = 0f;

    [Header("Limits")]
    public int maxPurchases = 0; // 0 = unlimited

    public int CalculatePrice(int purchasesSoFar, float globalMultiplier)
    {
        if (purchasesSoFar < 0) purchasesSoFar = 0;
        float growth = Mathf.Pow(priceGrowth, purchasesSoFar);
        float p = (basePrice * growth) + (priceAddPerPurchase * purchasesSoFar);
        p *= globalMultiplier;
        if (p < 0f) p = 0f;
        return Mathf.CeilToInt(p);
    }

    public bool IsMaxed(int purchasesSoFar)
    {
        return maxPurchases > 0 && purchasesSoFar >= maxPurchases;
    }
}

public class ShopManager : MonoBehaviour
{
    public PlayerStats player;
    public ShopItemDefinition[] items;

    [Header("Purchase State (Public)")]
    public int[] purchases;

    void Awake()
    {
        if (player == null) player = FindFirstObjectByType<PlayerStats>();
        if (items == null) items = new ShopItemDefinition[0];

        if (purchases == null || purchases.Length != items.Length)
            purchases = new int[items.Length];

        for (int i = 0; i < purchases.Length; i++)
            purchases[i] = Mathf.Max(0, purchases[i]);
    }

    public int GetPurchases(string itemId)
    {
        int idx = FindIndex(itemId);
        if (idx < 0) return 0;
        return purchases[idx];
    }

    public int GetPrice(string itemId)
    {
        int idx = FindIndex(itemId);
        if (idx < 0 || player == null) return int.MaxValue;
        return items[idx].CalculatePrice(purchases[idx], player.shopPriceMultiplier);
    }

    public bool CanBuy(string itemId)
    {
        int idx = FindIndex(itemId);
        if (idx < 0 || player == null) return false;
        if (items[idx].IsMaxed(purchases[idx])) return false;
        int price = items[idx].CalculatePrice(purchases[idx], player.shopPriceMultiplier);
        return player.currency >= price;
    }

    public bool TryBuy(string itemId)
    {
        int idx = FindIndex(itemId);
        if (idx < 0 || player == null) return false;

        var def = items[idx];
        if (def.IsMaxed(purchases[idx])) return false;

        int price = def.CalculatePrice(purchases[idx], player.shopPriceMultiplier);
        if (!player.SpendCurrency(price)) return false;

        ApplyItemEffect(def);
        purchases[idx] += 1;
        return true;
    }

    void ApplyItemEffect(ShopItemDefinition def)
    {
        switch (def.type)
        {
            case ShopItemType.Heal:
                player.Heal(def.intAmount);
                break;

            case ShopItemType.MaxHealthUpgrade:
                player.SetMaxHealth(player.maxHealth + def.intAmount, false);
                if (def.floatAmount > 0f)
                {
                    int extra = Mathf.RoundToInt(player.maxHealth * def.floatAmount);
                    player.SetMaxHealth(player.maxHealth + extra, false);
                }
                break;

            case ShopItemType.BaseDamageUpgrade:
                player.baseDamage += def.intAmount;
                break;

            case ShopItemType.DamageMultiplierUpgrade:
                player.damageMultiplier += def.floatAmount;
                if (player.damageMultiplier < 0f) player.damageMultiplier = 0f;
                break;

            case ShopItemType.FlatDamageUpgrade:
                player.flatDamageBonus += def.intAmount;
                break;

            case ShopItemType.ArmorUpgrade:
                player.armor += def.intAmount;
                if (player.armor < 0) player.armor = 0;
                break;

            case ShopItemType.DamageReductionUpgrade:
                player.damageReduction += def.floatAmount;
                if (player.damageReduction < 0f) player.damageReduction = 0f;
                if (player.damageReduction > 0.95f) player.damageReduction = 0.95f;
                break;
        }

        player.ClampAll();
    }

    int FindIndex(string itemId)
    {
        if (string.IsNullOrEmpty(itemId) || items == null) return -1;
        for (int i = 0; i < items.Length; i++)
            if (items[i] != null && items[i].id == itemId)
                return i;
        return -1;
    }
}

public class CombatDemo : MonoBehaviour
{
    public PlayerStats player;
    public PlayerStats enemy;

    [Header("Enemy Stats (Public)")]
    public int enemyMaxHealth = 50;
    public int enemyHealth = 50;
    public int enemyBaseDamage = 6;
    public int enemyArmor = 0;
    public float enemyDamageReduction = 0f;

    void Awake()
    {
        if (player == null) player = FindFirstObjectByType<PlayerStats>();
        ResetEnemy();
    }

    public void ResetEnemy()
    {
        enemyMaxHealth = Mathf.Max(1, enemyMaxHealth);
        enemyHealth = enemyMaxHealth;
    }

    public int PlayerAttackEnemy()
    {
        if (player == null) return 0;
        int dmg = player.CalculateOutgoingDamage(true);
        int dealt = ApplyDamageToEnemy(dmg);
        return dealt;
    }

    public int EnemyAttackPlayer()
    {
        if (player == null) return 0;
        int dmg = Mathf.Max(0, enemyBaseDamage);
        int dealt = player.TakeDamage(dmg);
        return dealt;
    }

    int ApplyDamageToEnemy(int incomingDamage)
    {
        int reduced = Mathf.Max(0, incomingDamage - Mathf.Max(0, enemyArmor));
        float afterPercent = reduced * (1f - Mathf.Clamp(enemyDamageReduction, 0f, 0.95f));
        int final = Mathf.Max(0, Mathf.RoundToInt(afterPercent));
        enemyHealth = Mathf.Clamp(enemyHealth - final, 0, enemyMaxHealth);
        return final;
    }
}

public class IAPCurrencyGrant : MonoBehaviour, IStoreListener
{
    [Header("Refs")]
    public PlayerStats player;

    [Header("Product IDs (as configured in stores)")]
    public string productIdSmall = "currency_small";
    public string productIdMedium = "currency_medium";
    public string productIdLarge = "currency_large";

    [Header("Grants (Public)")]
    public int grantSmall = 100;
    public int grantMedium = 550;
    public int grantLarge = 1200;

    IStoreController controller;
    IExtensionProvider extensions;

    void Awake()
    {
        if (player == null) player = FindFirstObjectByType<PlayerStats>();
    }

    public void InitializeIAP()
    {
        var builder = ConfigurationBuilder.Instance(StandardPurchasingModule.Instance());

        if (!string.IsNullOrEmpty(productIdSmall))
            builder.AddProduct(productIdSmall, ProductType.Consumable);
        if (!string.IsNullOrEmpty(productIdMedium))
            builder.AddProduct(productIdMedium, ProductType.Consumable);
        if (!string.IsNullOrEmpty(productIdLarge))
            builder.AddProduct(productIdLarge, ProductType.Consumable);

        UnityPurchasing.Initialize(this, builder);
    }

    public void BuySmall() => Buy(productIdSmall);
    public void BuyMedium() => Buy(productIdMedium);
    public void BuyLarge() => Buy(productIdLarge);

    public void Buy(string productId)
    {
        if (controller == null || string.IsNullOrEmpty(productId)) return;
        controller.InitiatePurchase(productId);
    }

    public void OnInitialized(IStoreController controller, IExtensionProvider extensions)
    {
        this.controller = controller;
        this.extensions = extensions;
    }

    public void OnInitializeFailed(InitializationFailureReason error) { }

#if UNITY_2022_2_OR_NEWER
    public void OnInitializeFailed(InitializationFailureReason error, string message) { }
#endif

    public PurchaseProcessingResult ProcessPurchase(PurchaseEventArgs purchaseEvent)
    {
        if (player == null) return PurchaseProcessingResult.Complete;

        string id = purchaseEvent.purchasedProduct.definition.id;

        if (id == productIdSmall) player.AddCurrency(grantSmall);
        else if (id == productIdMedium) player.AddCurrency(grantMedium);
        else if (id == productIdLarge) player.AddCurrency(grantLarge);

        return PurchaseProcessingResult.Complete;
    }

    public void OnPurchaseFailed(Product product, PurchaseFailureReason failureReason) { }
}